package main

import "fmt"

func zeroFilledSubarray(nums []int) int64 {
	starts, ends := make([]int, 0), make([]int, 0)
	start := -1
	for idx, num := range nums {
		if num == 0 && start == -1 {
			starts = append(starts, idx)
			start = idx
		} else if num != 0 && start != -1 {
			ends = append(ends, idx-1)
			start = -1
		}

		if idx == len(nums)-1 && start != -1 {
			ends = append(ends, idx)
		}
	}

	count := 0
	for run := 0; run < len(starts); run++ {
		length := ends[run] - starts[run]
		for zidx := 0; zidx <= length; zidx++ {
			count += length - zidx + 1
		}
	}

	return int64(count)
}

